#include<bits/stdc++.h>
using namespace std;
int n,m,root,dfn[1000010],low[1000010],dfncnt,flag[1000010],a,b;
vector<int> mp[1000010];
void tarjan(int x)
{
    dfn[x]=low[x]=++dfncnt;
    for(int v:mp[x])
    {
        if(!dfn[v])
        {
            tarjan(v);
            low[x]=min(low[x],low[v]);
            if(low[v]>=dfn[x]&&a!=x&&dfn[b]>=dfn[v])
            {
                flag[x]=1;
            }
        }
        else
        {
            low[x]=min(low[x],dfn[v]);
        }
    }
}
int main()
{
    scanf("%d",&n);
    int u,v;
    while(scanf("%d%d",&u,&v)==2&&u)
    {
        mp[u].push_back(v);
        mp[v].push_back(u);
    }
    scanf("%d%d",&a,&b);
    tarjan(a);
    for(int i=1;i<=n;i++)
    {
        if(flag[i])
        {
            printf("%d",i);
            return 0;
        }
    }
    printf("No solution");
    return 0;
}
